<template><div class="table-wrap"><table><thead><tr><th>Platz</th><th>Spieler</th><th>Punkte</th><th>Spiele</th><th>Siege</th><th>Ø</th></tr></thead><tbody><tr v-for="(row,index) in rows" :key="row.id"><td class="place">{{ medal(index) }}</td><td><b>{{ row.name }}</b></td><td>{{ row.points }}</td><td>{{ row.games }}</td><td>{{ row.wins }}</td><td>{{ row.avg }}</td></tr></tbody></table></div></template>
<script setup>defineProps({rows:Array});function medal(i){return i===0?'🥇':i===1?'🥈':i===2?'🥉':i+1}</script>
